  ('love', 'ความรักความสัมพันธ์', 'ชวนมองความรัก ความคาดหวัง และวิธีดูแลกัน', '#f3b8c6', 2),
  ('memory', 'ความหลังและความฝัน', 'ย้อนดูเรื่องที่ผ่านมา แล้วเปิดพื้นที่ให้อนาคต', '#b9d9f2', 3),
