  ((select id from public.categories where slug = 'icebreaker'), 'ช่วงนี้มีเรื่องเล็ก ๆ อะไรที่ทำให้คุณยิ้มได้โดยไม่ต้องพยายาม', 'เล่าภาพ เหตุการณ์ หรือคนที่อยู่ในโมเมนต์นั้นก็ได้', 1, array['อารมณ์', 'ชีวิตประจำวัน']),
  ((select id from public.categories where slug = 'icebreaker'), 'ถ้าวันนี้เป็นหน้าหนึ่งในไดอารี่ คุณอยากตั้งชื่อหน้านี้ว่าอะไร', 'เลือกชื่อที่ตรงกับความรู้สึกมากกว่าความสมบูรณ์แบบ', 1, array['ตัวตน', 'อารมณ์']),
  ((select id from public.categories where slug = 'icebreaker'), 'คุณชอบตัวเองตอนอยู่กับคนแบบไหนมากที่สุด', 'ลองนึกถึงคนที่ทำให้คุณรู้สึกเป็นตัวเองได้ง่าย', 2, array['ตัวตน', 'ความสัมพันธ์']),
  ((select id from public.categories where slug = 'icebreaker'), 'ถ้าความเหนื่อยของคุณพูดได้ มันน่าจะกำลังขออะไรจากคุณ', 'ตอบแบบซื่อตรงกับร่างกายและใจในตอนนี้', 2, array['ดูแลใจ', 'อารมณ์']),
  ((select id from public.categories where slug = 'icebreaker'), 'นิสัยเล็ก ๆ ข้อไหนของคุณที่อยากให้คนใกล้ตัวเข้าใจมากขึ้น', 'อธิบายด้วยความเมตตาต่อตัวเอง', 2, array['ตัวตน', 'การเข้าใจ']),
  ((select id from public.categories where slug = 'icebreaker'), 'ถ้ามีเวลาว่างหนึ่งวันเต็มโดยไม่ต้องรู้สึกผิด คุณจะใช้วันนั้นอย่างไร', 'ไม่ต้องตอบให้ดูมีประโยชน์ ตอบให้จริงกับใจ', 1, array['พักผ่อน', 'ความสุข']),
  ((select id from public.categories where slug = 'icebreaker'), 'คุณรู้สึกปลอดภัยที่สุดเมื่อคนอื่นปฏิบัติกับคุณแบบไหน', 'อาจเป็นน้ำเสียง การฟัง หรือพื้นที่ที่เขาเว้นให้คุณ', 3, array['พื้นที่ปลอดภัย', 'ความสัมพันธ์']),
  ((select id from public.categories where slug = 'icebreaker'), 'ช่วงนี้คุณกำลังพยายามเก่งเรื่องอะไรอยู่ แม้คนอื่นอาจไม่เห็น', 'ให้เครดิตความพยายามเล็ก ๆ ของตัวเอง', 2, array['เติบโต', 'กำลังใจ']),
  ((select id from public.categories where slug = 'icebreaker'), 'มีคำชมแบบไหนที่คุณได้รับแล้วจำได้นานเป็นพิเศษ', 'เล่าว่าคำนั้นแตะส่วนไหนในใจคุณ', 1, array['ความทรงจำ', 'คุณค่า']),
