  ((select id from public.categories where slug = 'love'), 'มีเรื่องใดที่คุณอยากให้คนรักหรือคนสนิทถามคุณบ่อยขึ้น', 'คำถามนั้นอาจสะท้อนสิ่งที่คุณอยากได้รับการมองเห็น', 3, array['การสื่อสาร', 'ความต้องการ']),
