  ((select id from public.categories where slug = 'memory'), 'ความทรงจำวัยเด็กเรื่องไหนที่ยังส่งผลกับคุณในวันนี้', 'เล่าเท่าที่สบายใจ ทั้งด้านอบอุ่นหรือด้านที่ยังเจ็บอยู่', 4, array['วัยเด็ก', 'ตัวตน']),
