  ((select id from public.categories where slug = 'memory'), 'ถ้าอีกห้าปีข้างหน้ามองย้อนกลับมาวันนี้ คุณอยากภูมิใจเรื่องอะไร', 'ตอบเป็นการกระทำเล็ก ๆ ที่เริ่มได้จริงก็ได้', 2, array['อนาคต', 'การเติบโต']),
