  ((select id from public.categories where slug = 'memory'), 'มีเรื่องไหนที่คุณเคยคิดว่าเสียไปแล้ว แต่จริง ๆ มันเปลี่ยนรูปมาอยู่กับคุณ', 'ลองมองอดีตแบบไม่รีบสรุปว่ามันเป็นเพียงการสูญเสีย', 4, array['สูญเสีย', 'เยียวยา']),
