  ((select id from public.categories where slug = 'family'), 'ในบ้านของคุณ ใครคือคนที่ทำให้คำว่าอดทนมีความหมาย', 'เล่าด้วยความอ่อนโยนต่อคนคนนั้นและต่อตัวเอง', 3, array['ความอดทน', 'ความทรงจำ']),
